final:
module top_module(
    input signed [7:0] obf_A,
    input signed [7:0] B,
    input [1:0] Op,
    output reg signed [7:0] C
);always @(*) begin
    case (Op)
        2'b00: C = obf_A + B;
        2'b01: C = obf_A - B;
        2'b10: C = obf_A * B;
        2'b11: C = obf_A / B;
    endcase
end

endmodule
